using System.Collections;
using UnityEngine;
using Cinemachine;

/// <summary>
/// CameraManager — shake de câmara (Tarefa #21): impacto ao levar dano
/// (<see cref="ShakeHit"/>), e shake genérico parametrizável usado por
/// PlayerFeedback (morte) e Action_ShakeCamera (Etapa 6).
/// </summary>
public partial class CameraManager
{
    [Header("Shake on Hit")]
    [SerializeField] private float hitShakeAmplitude = 1.2f;
    [SerializeField] private float hitShakeFrequency = 2.0f;
    [SerializeField] private float hitShakeDuration = 0.18f;

    private Coroutine shakeRoutine;

    public void ShakeHit()
    {
        Shake(hitShakeAmplitude, hitShakeFrequency, hitShakeDuration);
    }

    /// <summary>
    /// Aplica um shake de câmara com amplitude/frequência/duração personalizadas
    /// (ex: Action_ShakeCamera, Etapa 6) — útil para impactos de boss, explosões,
    /// quedas, etc., além do shake automático de ShakeHit(). Aplica-se à vcam
    /// realmente activa no momento (incluindo vcamManual, durante uma cutscene).
    ///
    /// Respeita <see cref="GameSettings.ScreenShakeEnabled"/> (Tarefa #40):
    /// se o jogador desligou o screen shake nas Opções, este método não faz nada.
    /// </summary>
    public void Shake(float amplitude, float frequency, float duration)
    {
        // Tarefa #40 — acessibilidade: não aplicar shake se desligado nas Opções.
        if (GameSettings.Instance != null && !GameSettings.Instance.ScreenShakeEnabled) return;

        var v = GetActiveVcam() ?? vcamNormal;
        if (v == null) return;

        if (shakeRoutine != null) StopCoroutine(shakeRoutine);
        shakeRoutine = StartCoroutine(DoShake(v, amplitude, frequency, duration));
    }

    private IEnumerator DoShake(CinemachineVirtualCamera vcam, float amp, float freq, float duration)
    {
        if (vcam == null) yield break;

        var noise = vcam.GetCinemachineComponent<CinemachineBasicMultiChannelPerlin>();
        if (noise == null) yield break;

        float oldAmp = noise.m_AmplitudeGain;
        float oldFreq = noise.m_FrequencyGain;

        noise.m_AmplitudeGain = amp;
        noise.m_FrequencyGain = freq;

        yield return new WaitForSeconds(duration);

        noise.m_AmplitudeGain = oldAmp;
        noise.m_FrequencyGain = oldFreq;
    }
}
